import{_ as o,c as a,o as r,a1 as t}from"./chunks/framework.TuIRSVI8.js";const m=JSON.parse('{"title":"Bazzite (Fedora Atomic) Notes","description":"","frontmatter":{},"headers":[],"relativePath":"Bazzite.md","filePath":"Bazzite.md","lastUpdated":1765863345000}'),i={name:"Bazzite.md"};function l(s,e,d,c,n,u){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="bazzite-fedora-atomic-notes" tabindex="-1">Bazzite (Fedora Atomic) Notes <a class="header-anchor" href="#bazzite-fedora-atomic-notes" aria-label="Permalink to &quot;Bazzite (Fedora Atomic) Notes&quot;">​</a></h1><h2 id="system-snapshot" tabindex="-1">System Snapshot <a class="header-anchor" href="#system-snapshot" aria-label="Permalink to &quot;System Snapshot&quot;">​</a></h2><ul><li>Hostname: steambox</li><li>OS: Bazzite 43.20251210.1 (Fedora Atomic/rpm-ostree)</li><li>User: deck (UID/GID 1000)</li><li>Layered rpm-ostree packages (current): <code>1password</code>, <code>1password-cli</code>, <code>zsh</code>, <code>moby-engine</code>, <code>docker-buildx</code>, <code>docker-compose-switch</code>, <code>ulauncher</code></li><li>Planned next layer: <code>wmctrl</code> (for reliable <code>ulauncher-toggle</code> focus)</li></ul><h2 id="container-runtime-policy" tabindex="-1">Container Runtime Policy <a class="header-anchor" href="#container-runtime-policy" aria-label="Permalink to &quot;Container Runtime Policy&quot;">​</a></h2><ul><li><strong>Default:</strong> Podman (preinstalled). Use podman/podman-compose; prefer Podman-first for day-to-day containers.</li><li><strong>Podman shim for docker CLI:</strong> optional <code>podman-docker</code> RPM (not installed).</li><li><strong>If you truly need Docker Engine/Compose on host (mutable choice):</strong><ol><li><code>sudo rpm-ostree install moby-engine docker-compose-plugin docker-buildx-plugin</code></li><li>Reboot → <code>sudo systemctl enable --now docker</code></li><li><code>sudo usermod -aG docker $USER</code> → relog/newgrp Notes: layers persist across normal rpm-ostree upgrades; re-check only after a rebase to a different image.</li></ol></li><li><strong>Safer alternative:</strong> run Docker inside a dedicated distrobox and export the CLI; keeps host immutable.</li></ul><h2 id="docs-scripts" tabindex="-1">Docs &amp; Scripts <a class="header-anchor" href="#docs-scripts" aria-label="Permalink to &quot;Docs &amp; Scripts&quot;">​</a></h2><ul><li>Bootstrap: <code>scripts/bazzite-bootstrap.sh</code> (see <code>docs/BAZZITE_BOOTSTRAP.md</code> for full flow).</li><li>Tooling/layers philosophy: <code>docs/BAZZITE_TOOLS.md</code> (host vs distrobox vs rpm-ostree).</li><li>Recovery/immutable OS guidance: <code>docs/RECOVERY_INSTRUCTIONS.md</code>.</li></ul><h2 id="to-do-if-enabling-host-docker" tabindex="-1">To Do (if enabling host Docker) <a class="header-anchor" href="#to-do-if-enabling-host-docker" aria-label="Permalink to &quot;To Do (if enabling host Docker)&quot;">​</a></h2><ul><li>Decide on host Docker vs Podman-only vs docker-in-distrobox.</li><li>If host Docker: layer moby packages (above), enable service, add user to docker group.</li><li>Once container runtime is chosen, run the media stack (Swarm/compose) with <code>.env.local</code> secrets.</li></ul><h2 id="desktop-qol" tabindex="-1">Desktop QoL <a class="header-anchor" href="#desktop-qol" aria-label="Permalink to &quot;Desktop QoL&quot;">​</a></h2><ul><li>Ulauncher is layered; after reboot set GNOME shortcut to <code>ulauncher-toggle</code> (suggested: Super+Space). Install/layer <code>wmctrl</code> for window focus reliability.</li></ul><h2 id="rpm-ostree-guardrails-read-before-layering" tabindex="-1">rpm-ostree Guardrails (read before layering) <a class="header-anchor" href="#rpm-ostree-guardrails-read-before-layering" aria-label="Permalink to &quot;rpm-ostree Guardrails (read before layering)&quot;">​</a></h2><ul><li>Layering is a <strong>last resort</strong>; Bazzite docs warn it can block updates/rebases until removed. Reboot is always required after layering. Prefer Flatpak/Distrobox/brew first. citeturn0search1</li><li>Layered packages <strong>persist across updates/rebases</strong>; conflicts can be resolved with <code>rpm-ostree reset</code> or uninstalling the layer. citeturn0search4</li><li>If layering third-party COPR/RPM: add repo, layer package, reboot; if updates fail, remove the repo and the layered package, then retry.</li></ul><h2 id="ulauncher-hotkey-wayland" tabindex="-1">Ulauncher hotkey (Wayland) <a class="header-anchor" href="#ulauncher-hotkey-wayland" aria-label="Permalink to &quot;Ulauncher hotkey (Wayland)&quot;">​</a></h2><ol><li>Ensure <code>wmctrl</code> is layered (already queued).</li><li>Set Ulauncher’s built-in hotkey to an unused combo.</li><li>GNOME Settings → Keyboard → Custom Shortcut → command <code>ulauncher-toggle</code>, bind to Super+Space. citeturn0search0</li></ol>',15)])])}const p=o(i,[["render",l]]);export{m as __pageData,p as default};
